  float nu = log(max(0.000001, logZn / log(2.0))) / log(2.0);
  float smoothIteration = float(iteration) + 1.0 - nu;
  float t = clamp(smoothIteration / float(u_max_iter), 0.0, 1.0);
  vec3 color = palette(t);
  return mix(color * color, color, 0.35);
}

